#!/usr/bin/env python3
"""Generate the active candidate-complete W3.5 task queue."""
from __future__ import annotations
from pathlib import Path
from report_link_utils import markdown_link

ROOT=Path(__file__).resolve().parents[1]
OUT=ROOT/'docs/planning/next-actions.md'
STATUS=ROOT/'docs/reports/project-status-generated.md'
GAP=ROOT/'docs/reports/research-gap-report.md'
TASKS=[
{"id":"STRATEGIC-004","priority":"high","title":"Complete W3.5 machinery cost, claim-impact, and preserved-failure closure","why":"Corpus, factorization, registered discrimination, qualified FARA-specificity, and all twelve registered candidate tests are complete. W3.5 still cannot close until architecture and derived-machinery costs are fully accounted, every bounded result is propagated to the correct claim track, and all negative results, reintroduced machinery, disputed cases, and nonclaims are preserved in immutable closure artifacts.","affected":["docs/research/w3-5-specificity-and-discovery-gate-v1.0.md","theory/evaluation/w3-5-specificity-and-discovery-gate.json","theory/evaluation/w3-5-candidate-test-result-v1.0.json","theory/evaluation/central-claim-registry.json","theory/evaluation/research-gates.json"],"outcome":"Complete W35-COST-RESULT, W35-CLAIM-RESULT, and W35-FAILURE-RESULT with linked immutable evidence, then resolve W3.5 only if every authorization condition is satisfied without erasing the qualified-negative specificity result or the no-indispensable-candidate result.","risk":"high","branch":"research/close-w3-5-adjudication","pr":"Close W3.5 machinery, claim-impact, and failure audit"},
{"id":"STRATEGIC-005","priority":"blocked","title":"Assemble the finite-core theorem or strongest obstruction","why":"ASM-SC-001 through ASM-SC-003 remain open. W4 and all bounded W3.5 experimental stages through candidate testing are complete, but W5 remains blocked until cost, claim-impact, and preserved-failure artifacts close W3.5.","affected":["docs/research/s-core-construction-obstruction-ledger-v1.0.md","theory/evaluation/s-core-construction-obstruction-ledger.json","theory/evaluation/thm-target-001.json","theory/evaluation/central-claim-registry.json"],"outcome":"A bounded REP theorem, equivalence, countermodel, proper-subclass result, impossibility result, or explicit unresolved result consistent with every completed positive and negative W3.5 finding.","risk":"high","branch":"research/assemble-s-core-result","pr":"Assemble S_core theorem or obstruction"}]

def nav_links(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(STATUS,OUT)}",f"- Research Gaps: {markdown_link(GAP,OUT)}",f"- Next Actions: {markdown_link(OUT,OUT)}"]

def main()->int:
    ids=[x['id'] for x in TASKS]; assert len(ids)==len(set(ids))
    lines=['# Next Actions','','## Navigation','',*nav_links(),'','Generated by `python tools/generate_next_tasks.py` under the separated REP, ADJ, and USD program.','','W0-W4 are complete bounded REP packages. Corpus freeze, bounded GREL-FARA factorization, registered discrimination, qualified FARA-specificity, and all twelve registered candidate tests are complete. No registered candidate is indispensable within the frozen class, but this does not resolve universal structure. Machinery/cost, claim-impact, and preserved-failure closure are next; W5 remains blocked.','','## Ranked Next Actions','']
    for task in TASKS:
        affected=[markdown_link(ROOT/path,OUT) for path in task['affected']]
        lines += [f"### {task['id']}: {task['title']}",'','- Source: central research program',f"- Priority: {task['priority']}",f"- Why it matters: {task['why']}",'- Affected files:',*[f'  - {item}' for item in affected],f"- Expected outcome: {task['outcome']}",f"- Risk level: {task['risk']}",f"- Suggested branch name: `{task['branch']}`",f"- Suggested PR title: `{task['pr']}`",'']
    lines += ['## Maintainer Task Briefs','','Each task must preserve `THM-TARGET-001`, `THM-US-TARGET-001`, `FAITHFUL-REP-001`, `P8-ROLE-001`, W0-W4, `RCS-CORPUS-001`, `W35-FACTOR-RESULT-001`, `W35-SCOPE-RESULT-001`, `W35-SPEC-RESULT-001`, `W35-CANDIDATE-RESULT-001`, both disputed cases, all negative results, reintroduced machinery, equivalent-reintroduction findings, and nonclaims. Do not retroactively alter admission, licensing, factorization, specificity, or candidate records. Do not infer universal nonexistence from the bounded candidate result. Do not begin W5 while `W3.5-SDG-001` remains unresolved or lacks linked immutable evidence.','','Validation commands:','','- `make research-check`','- `make health-fast`','','## Navigation','',*nav_links()]
    OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(f"{OUT.relative_to(ROOT)} tasks={len(TASKS)}"); return 0

if __name__=='__main__': raise SystemExit(main())
